<template>
    <body style=" background-image: url('https://vorteks.pythonanywhere.com/media/files/bg_image_2.webp');">
        <div class="mycon">
            <form @submit.prevent = 'submitLogin'>
                <input type="text" class="form-control" name="username" id="" placeholder="username" v-model="credentials.username" required>
                <input type="password" class="form-control" name="password" placeholder="password" v-model="credentials.password" required>
                <input type="submit" value="Login" class="btn btn-theme mt-3 wow fadeInUp ml-1">
                <div v-if="response">
                    <span>{{ response }}</span>
                </div>
            </form>
        </div>
    </body>
</template>

<style scoped>
.mycon{
    padding: 2rem;
    min-width: 350px
}
body{
    width: 100vw;
    height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: space-around;
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
    /* padding: 40vh 0 0 40vw ; */
}
form{
    padding: 2rem;
    display: flex;
    flex-direction: column;
    min-width: 350px;
}
</style>

<script>
import { mapState, mapActions } from 'vuex';

export default {
    data() {
        return{
            credentials:{
                username: '',
                password: '',
            },
            // response: this.response,
        };
    },
  computed: {
    ...mapState('auth',['isAuthenticated', 'response']),
  },
  methods: {
    ...mapActions('auth',['login']),
    async submitLogin() {
        try{
              if (!this.credentials.username || !this.credentials.password) {
          this.$store.commit('setResponse', 'Please enter both username and password.');
          return;
        }
            const formData = new FormData();
                formData.append('username', this.credentials.username);
                formData.append('password', this.credentials.password);
            await this.login(formData);
                if (this.isAuthenticated){
                    this.$router.push('/').reload
                }
                else{
                    alert('We have a problem')
                }
            }
            catch (error){
                console.error( 'Error', error);
            }
        }
    }
}
</script>