import axios from 'axios';

const state = {
  // user: null,
  userdata: null,
  isAuthenticated: false,
  authToken: null,
  csrfToken: null,
  response: null,
  returnmessage: false
};
const mutations = {
    setAuth(state, isAuthenticated){
        state.isAuthenticated = isAuthenticated
    },
  setAuthToken(state, authToken) {
    state.authToken = authToken
  }, 
  setCsrf(state, csrfToken,) {
      state.csrfToken = csrfToken;
   },
  setResponse(state, response){
    state.response = response
  },
  setUserInfo(state, userdata){
    state.userdata = userdata
  },
  setReturnMessage(state, returnmessage){
    state.returnmessage = returnmessage
  }

};

const actions = {
  async logout({ commit }) {
    try {
        await axios.post('https://vorteks.pythonanywhere.com/api/logout/');
        commit('setAuth', false);
        localStorage.removeItem('csrf_token');
        localStorage.removeItem('auth_token');
    } catch (error) {
        console.error('Logout Error', error);
    }
},
  
async login({ commit }, credentials) {
  try {
    const response = await axios.post('https://vorteks.pythonanywhere.com/api/login/', credentials, {
      headers: {
        'Content-Type': 'application/json',
      },
    });
    
    if (response.status === 200 && response.data.message === 'Login successful') {
      commit('setAuth', true)
      const authToken = response.data.access_token;
      const csrfToken = response.data.csrf_token;
      commit('setAuthToken', authToken)
      commit('setCsrf', csrfToken)
    localStorage.setItem('csrf_token', csrfToken);
    localStorage.setItem('auth_token', authToken);
    } else {
      commit('setResponse', response.data.error)
      console.error('Login failed');
    }
  } catch (error) {
    console.error('Login Error', error);
  }
},
async getUser({ commit }) {
  try {
      const response = await axios.get('https://vorteks.pythonanywhere.com/api/user/',{
        headers: {
          Authorization: `Bearer ${state.authToken}`,
        },
      });
      if (response.status === 200) {
          const cuser = response.data
          commit('setUserInfo', cuser);
          console.log(cuser)
      } else {
          console.log('Tester')
      }
  } catch (error) {
      console.error('Fetch User Info Error', error);
  }
},
async addBlog({ commit }) {
  try {
      const response = await axios.post('https://vorteks.pythonanywhere.com/api/blogs/',{
        headers: {
          'Content-Type': 'application/json',
          'X-CSRFToken': state.csrfToken,
          Authorization: `Bearer ${state.authToken}`,
        },
      });
      if (response.status === 200) {
          console.log(response.data)
          commit('setReturnMessage', true);
      } else {
          console.log(response.data)
      }
  } catch (error) {
      console.error('Fetch User Info Error', error);
  }
},
};
export default {
  namespaced: true,
  state,
  mutations,
  actions,
};
