<template>
    <div class="vg-page page-contact" id="contact">
                <h1 class="text-center fg-dark wow fadeInUp">Contact</h1>
                <div class="container-fluid">
                    <div class="row py-5">
                    <div class="col-lg-7 wow zoomIn">
                        <div class="vg-maps">
                            <img :src="brand" alt="" style="width: 100%; height: 100%;">
                        </div>
                    </div>
                    <div class="col-lg-5">
                        <form class="vg-contact-form" @submit.prevent="submit" >
                        <div class="form-row">
                            <div class="col-12 wow fadeInUp">
                                <input class="form-control" v-model="cfd.name" type="text" name="name" id="" placeholder="Your Name" autocomplete="off" required>
                            </div>
                            <div class="col-6 wow fadeInUp">
                                <input class="form-control" v-model="cfd.email" type="email" name="email" id="" placeholder="Email" autocomplete="off" required>
                            </div>
                            <div class="col-6 wow fadeInUp">
                                <input class="form-control" v-model="cfd.subject" type="text" name="subject" id="" placeholder="Subject" required>
                            </div>
                            <div class="col-12 wow fadeInUp">
                                <textarea class="form-control" v-model="cfd.message" name="message" id="" cols="30" rows="10" placeholder="Enter Message Here" required></textarea>
                            </div>
                            <input type="submit" class="btn btn-theme mt-3 wow fadeInUp ml-1" value="Send Message">
                        </div>
                        <div v-if="contactmessage === true" class="message-from-server">
                            <span>Successful</span>
                        </div>
                        <div v-if="contactmessage === false" class="message-from-server">
                            <span>Failed Try Again Later</span>
                        </div>
                        </form>
                    </div>
                    </div>
                </div>
            </div>
</template>

<style>
.vg-maps {
    width: 100%;
    height: 450px;
    background-color: #f8f9fa;
}

.vg-contact-form {
    margin: 0 auto;
    padding: 30px 0;
    max-width: 400px;
}

.vg-contact-form .form-control {
    margin: 8px 0;
}
</style>

<script>
    import { mapState, mapActions, mapGetters } from 'vuex';
    export default{
        name: 'ContactSec',
        data() {
            return {
                cfd:{
                    name: '',
                    email: '',
                    subject: '',
                    message: '',
                },
            }
        },
        computed:{
            ...mapState('details',['contactmessage']),
            ...mapGetters('details',['files']),
            brand(){
                return this.files['Brand Picture']
            }
        },
        methods: {
            ...mapActions('details', ['submitForm']),
            submit(){
            const formData = new FormData();
                formData.append('name', this.cfd.name);
                formData.append('email', this.cfd.email);
                formData.append('subject', this.cfd.subject);
                formData.append('message', this.cfd.message);
                this.submitForm(formData)
                // axios.post(`https://vorteks.pythonanywhere.com/api/contactform/`, formData)
                // .then(() => {
                //     this.messageFromServer = response.data.message;
                    
                //     })
                //     .catch((error) => {
                //     console.error('Error sending contact message:', error);
                //     this.messageFromServer = 'An error occurred while sending the message. Please try again later.';
                //     });
            },
        },
    }
    
</script>