<template>
    <div class="container pt-5">
                <div class="row">
                    <div class="col-md-6 wow fadeInRight">
                    <h2 class="fw-normal">Education</h2>
                    <ul class="timeline mt-4 pr-md-5">
                        <li v-for="eduItem in edu" :key="eduItem.id">
                        <div class="title">{{ eduItem.date }}</div>
                        <div class="details">
                            <h5>{{ eduItem.name }}</h5>
                            <small class="fg-theme">{{ eduItem.location }}</small>
                            <p>{{ eduItem.post }}<br> <b>{{ eduItem.certification }}</b> </p>
                        </div>
                        </li>
                    </ul>
                    </div>
                    <div class="col-md-6 wow fadeInRight" data-wow-delay="200ms">
                    <h2 class="fw-normal">Experience</h2>
                    <ul class="timeline mt-4 pr-md-5">
                        <li v-for="expItem in exp" :key="expItem.id">
                            <div class="title">{{ expItem.date }}</div>
                            <div class="details">
                                <h5>{{ expItem.name }}</h5>
                                <small class="fg-theme">{{ expItem.location }}</small>
                            </div>
                        </li>
                    </ul>
                    </div>
                </div>
                </div>
</template>

<style>
.timeline {
    position: relative;
    display: block;
    list-style: none;
    padding-left: 0;
    width: 100%;
}

.timeline::before {
    content: '';
    position: absolute;
    top: 0;
    bottom: 0;
    left: 0;
    margin: auto;
    width: 2px;
    height: 95%;
    background-color: #e3e5e9;
}

.timeline li {
    position: relative;
    display: block;
    padding-left: 30px;
    margin-bottom: 20px;
}

.timeline li::before {
    content: '';
    position: absolute;
    top: 8px;
    left: -8px;
    width: 18px;
    height: 18px;
    background-color: #747474;
    border: 3px solid #fff;
    border-radius: 50%;
}

.timeline li .title {
    width: 150px;
    padding: 6px 20px;
    background-color: #747474;
    color: #fff;
    font-weight: 500;
    border-radius: 30px 0 60px 30px;
}

.timeline li .details {
    background-color: #f4f5f8;
    margin-top: 8px;
    padding: 20px;
    border-radius: 4px;
}

.timeline li .details h5,
.timeline li .details p {
    margin-bottom: 0;
}

.timeline li .details small {
    display: block;
    font-weight: 500;
    font-size: 14px;
    margin-top: 5px;
    margin-bottom: 10px;
}
</style>

<script>
  import { mapState } from 'vuex';
    export default{
        computed:{
        ...mapState('details', ['edu', 'exp']),
    }
    }
</script>