<template>
    <div v-if="!loading">
        <BlogForm v-if="bfs" />
        <div class="vg-main-wrapper">
        <BlogHeader />
        <div class="vg-page page-blog">
            <div class="container">
            <div class="row widget-grid">
                <div class="col-lg-8">
                <div class="input-group py-2">
                    <input type="text" class="form-control" placeholder="Search" @input="search()" v-model="searchTerms" >
                </div>
                </div>
                <div class="col-lg-4">
                <div class="d-flex py-2 mx-n2">
                    <div class="input-group px-2">
                    <select v-model="selectedType" id="blogType" class="vg-select" @change="changeCategory()">
                        <option value="" selected disabled>Category</option>
                        <option value="All">All</option>
                        <option v-for=" choice in choices" :key= choice :value=choice> {{ choice }} </option>
                    </select>
                    </div>
                    <div class="input-group px-2">
                    <select class="vg-select" v-model="sorting" id="sortBy" @change="changeSort">
                        <option value="" selected disabled>Sort By</option>
                        <option value="title">Title</option>
                        <option value="date">Latest</option>
                    </select>
                    </div>
                </div>
                </div>
            </div>
            <div class="row post-grid">
                <div class="gridder my-3">
                        <div v-for="project in paginatedData" :key="project.id" class="grid-item wow zoomIn" :class="project.status">
                            <a class="img-place" :data-src="project.img" :href="project.url">
                                <img :src="project.img" alt="">
                                <div class="img-caption">
                                <h5 class="fg-theme">{{ project.name }}</h5>
                                <p>{{ project.about }}</p>
                                </div>
                            </a>
                        </div>
                    </div>
                    <div class="col-12 py-3">
                        <ul class="pagination justify-content-center">
                            <li class="page-item">
                            <button @click="prevPage" :disabled="currentPage === 1" class="page-link">Prev</button>
                            </li>
                            <li class="page-item">
                            <span href="" class="page-link">Page {{ currentPage }} of {{ TotalPages }}</span>
                            </li>
                            <li class="page-item">
                            <button @click="nextPage" :disabled="currentPage === TotalPages" class="page-link">Next</button>
                            </li>
                            <li v-if="csrfToken">
                            <button @click="openblogform" class="page-link">Add</button>
                            </li>
                        </ul>
                    </div>
            </div>
            </div>
        </div>
        </div>
    </div>
    <MyLoader v-else />
  </template>
    <script>
      import MyLoader from './MyLoader.vue'
    import BlogHeader from './BlogHeader.vue';
    import { mapState, mapGetters, mapMutations, mapActions } from 'vuex';
  import BlogForm from './BlogForm.vue';
    export default {
      components: {
        BlogHeader,
        BlogForm,
        MyLoader
      },
      data() {
        return {
          bfs: false,
          selectedType: '',
          sorting: '',
          searchTerms: '',
        };
      },
        created() {
        this.fetchDataFromDjango()
        this.setSorting('title')
        this.setCategory('All')
        },
      computed: {
        ...mapState('details', ['loading',
        'currentPage', 
        'itemsPerPage',
        'totalPages',
        'searchTerm'
      ]),
        ...mapState('auth', ['csrfToken']),
        ...mapGetters(
          'details', [
                      'choices',
                      'paginatedData',
                      'TotalPages',
                    ]),
      },
      methods: {
        ...mapActions(
          'details', [
                      'fetchDataFromDjango'
                    ]),
        ...mapMutations(
          'details', [
                      'setCategory', 
                      'setSorting',
                      'setPages',
                      'setKey',
                      'setCpage'
                    ]),
        search(){
          this.setKey(this.searchTerms)
          this.setCpage(1)
        },
        changeCategory(){
            this.setCategory(this.selectedType)
            this.setCpage(1)
        },
        changeSort(){
            this.setSorting(this.sorting)
        },
        openblogform(){
          this.bfs = true
        },
        prevPage() {
          if (this.currentPage > 1) {
            this.setPages(this.currentPage - 1);
          }
        },
        nextPage() {
          if (this.currentPage < this.TotalPages) {
            this.setPages(this.currentPage + 1);
          }
        },
      },
    };
    </script>
    
    <style scoped>
    .grid-item .img-place{
      max-width: none;
    }
    </style>
    