import"../src/assets/vendor/nice-select/css/nice-select.css"
import"../src/assets/vendor/fancybox/css/jquery.fancybox.min.css"
import"../src/assets/css/virtual.css"
import"../src/assets/css/style.css"
import auth from './auth';
import details from './store'
import { createStore } from 'vuex';

const store = createStore({
    modules: {
      auth,
      details,
    }
  });

const router = createRouter({
    history: createWebHistory(),
    routes
})
// router.beforeEach((to, from, next) => {
//     if (to.meta.requiresAuth && !store.state.auth.csrfToken) {
//       next({ path: '/login' });
//     }
//   });

  const csrfToken = localStorage.getItem('csrf_token');
  if (csrfToken ) {
      store.commit('auth/setCsrf', csrfToken);
  }
  const authToken = localStorage.getItem('auth_token');
  if (authToken) {
      store.commit('auth/setAuthToken', authToken);
  }
  // router.beforeEach((to, from, next) => {
  //   if (!to.meta.requiresAuth && store.state.auth.isAuthenticated) {
  //     // Redirect to the login page if the route requires authentication and the user is not logged in.
  //     next({ path: '/' });
  //   } else {
  //     next();
  //   }
  // });
createApp(App)
.use(router)
.use(store)
.mount('#app');

