<template>
    <div class="vg-page page-about" id="about">
                <div class="container py-3">
                <div class="row">
                    <div class="col-md-6">
                    <div class="img-place wow zoomIn pfp">
                        <img :src="img" alt="Photo Profile">
                    </div>
                    </div>
                    <div class="col-md-6">
                    <div class="caption wow fadeInRight">
                        <h2 class="fg-dark">{{ name }}</h2>
                        <p class="fg-theme fw-medium">{{ job }}</p>
                        <ul class="theme-list">
                        <li class="fg-dark"><b>From:</b> {{ currently }}</li>
                        <li class="fg-dark"><b>Lives In:</b> {{ origin }}</li>
                        <li class="fg-dark"><b>Gender:</b> {{ gender }}</li>
                        </ul>
                    </div>
                    </div>
                </div>
                <SkillSec />
                <ResumeSec />
            </div>
    </div>
</template>

<style>
.page-about .img-place {
    margin: 16px auto;
    width: 250px;
    height: 250px;
}

.pfp{
    border-radius: 50%;
}

@media (min-width: 600px) {
    .page-about .img-place {
        width: 300px;
        height: 300px;
    }
}
</style>

<script>
  import { mapGetters } from 'vuex';
    import SkillSec from './SkillSec.vue';
    import ResumeSec from './ResumeSec.vue';
    export default{
    components :{
        SkillSec,
        ResumeSec
    },
    computed:{
        ...mapGetters('details', ['details', 'files']),
        name(){
            return this.details['Name']
        },
        job(){
            return this.details['Job Description']
        },
        origin(){
            return this.details['Origin']
        },
        currently(){
            return this.details['Currently']
        },
        gender(){
            return this.details['Gender']
        },
        img(){
            return this.files['Profile Picture']
        },
    }
}
</script>